#!/usr/bin/env bash
# overhead.sh — Routing-control overhead generated by the mesh daemon.
#
#   ./overhead.sh [window_seconds] [node ...]
#
# Measures the volume of routing control traffic (OLSRd HELLO/TC on UDP/698, or
# Babel on UDP/6696 — selected by VS_PROTO) by installing *counting-only*
# iptables rules and reading the packet/byte deltas over a window. No tcpdump
# required, and the rules don't alter packet flow. Cleans up on exit.
#
#   OUTPUT counters per node  = control traffic that node *generates*.
#   Sum of OUTPUT across nodes = total routing overhead injected into the mesh.
#   INPUT counters            = control traffic that node *receives*.
#
# Examples:
#   ./overhead.sh 20                       # all running SATs, 20 s window
#   ./overhead.sh 30 SAT-1 SAT-2 SAT-3
#   VS_PROTO=babel ./overhead.sh 20        # measure Babel instead
set -uo pipefail
. "$(dirname "$0")/lib.sh"

WINDOW="${1:-20}"; [ "${1:-}" ] && shift || true
NODES=("$@"); [ ${#NODES[@]} -eq 0 ] && mapfile -t NODES < <(sat_nodes)
[ ${#NODES[@]} -gt 0 ] || die "no target nodes"

PORT=$(ctrl_port)
CHAIN=VSNES_CNT
IPT=iptables-legacy

install_counters() {
    local n="$1"
    inx "$n" $IPT -N "$CHAIN" 2>/dev/null || inx "$n" $IPT -F "$CHAIN"
    # Non-terminating jumps (CHAIN is empty -> returns), so flow is unaffected.
    inx "$n" $IPT -C INPUT  -p udp --dport "$PORT" -j "$CHAIN" 2>/dev/null \
        || inx "$n" $IPT -I INPUT  1 -p udp --dport "$PORT" -j "$CHAIN"
    inx "$n" $IPT -C OUTPUT -p udp --dport "$PORT" -j "$CHAIN" 2>/dev/null \
        || inx "$n" $IPT -I OUTPUT 1 -p udp --dport "$PORT" -j "$CHAIN"
}
remove_counters() {
    local n="$1"
    inx "$n" $IPT -D INPUT  -p udp --dport "$PORT" -j "$CHAIN" 2>/dev/null
    inx "$n" $IPT -D OUTPUT -p udp --dport "$PORT" -j "$CHAIN" 2>/dev/null
    inx "$n" $IPT -F "$CHAIN" 2>/dev/null
    inx "$n" $IPT -X "$CHAIN" 2>/dev/null
}
# Read jump-rule counters from a base chain: prints "pkts bytes".
read_counter() { # node, chainname(INPUT|OUTPUT)
    inx "$1" $IPT -nvxL "$2" 2>/dev/null \
        | awk -v c="$CHAIN" '$3==c{p+=$1; b+=$2} END{print p+0, b+0}'
}

cleanup() { for n in "${NODES[@]}"; do remove_counters "$n"; done; }
trap cleanup EXIT

log "proto=$VS_PROTO control-port=udp/$PORT  window=${WINDOW}s  nodes=${#NODES[@]}"
for n in "${NODES[@]}"; do is_up "$n" && install_counters "$n"; done

declare -A IN0 OUT0
for n in "${NODES[@]}"; do
    is_up "$n" || continue
    IN0[$n]=$(read_counter "$n" INPUT); OUT0[$n]=$(read_counter "$n" OUTPUT)
done

log "sampling for ${WINDOW}s…"; sleep "$WINDOW"

csv="$RESULTS_DIR/overhead_${RUN_STAMP}.csv"
echo "timestamp,proto,node,window_s,out_pkts,out_bytes,out_pps,out_bps,in_pkts,in_bytes,in_pps,in_bps" >"$csv"

t_out_pkts=0; t_out_bytes=0; t_in_pkts=0; t_in_bytes=0
printf '\n  %-8s %10s %10s %10s %10s\n' node out_pps out_kbps in_pps in_kbps
for n in "${NODES[@]}"; do
    is_up "$n" || continue
    read -r in1p in1b <<<"$(read_counter "$n" INPUT)"
    read -r o1p  o1b  <<<"$(read_counter "$n" OUTPUT)"
    read -r in0p in0b <<<"${IN0[$n]}"
    read -r o0p  o0b  <<<"${OUT0[$n]}"
    dop=$((o1p-o0p));  dob=$((o1b-o0b))
    dip=$((in1p-in0p)); dib=$((in1b-in0b))
    opps=$(awk -v x="$dop" -v w="$WINDOW" 'BEGIN{printf "%.2f", x/w}')
    obps=$(awk -v x="$dob" -v w="$WINDOW" 'BEGIN{printf "%.0f", x*8/w}')
    ipps=$(awk -v x="$dip" -v w="$WINDOW" 'BEGIN{printf "%.2f", x/w}')
    ibps=$(awk -v x="$dib" -v w="$WINDOW" 'BEGIN{printf "%.0f", x*8/w}')
    echo "$(date -Iseconds),$VS_PROTO,$n,$WINDOW,$dop,$dob,$opps,$obps,$dip,$dib,$ipps,$ibps" >>"$csv"
    printf '  %-8s %10s %10s %10s %10s\n' "$n" "$opps" \
        "$(awk -v b="$obps" 'BEGIN{printf "%.1f", b/1000}')" "$ipps" \
        "$(awk -v b="$ibps" 'BEGIN{printf "%.1f", b/1000}')"
    t_out_pkts=$((t_out_pkts+dop)); t_out_bytes=$((t_out_bytes+dob))
    t_in_pkts=$((t_in_pkts+dip));   t_in_bytes=$((t_in_bytes+dib))
done

echo "$(date -Iseconds),$VS_PROTO,TOTAL,$WINDOW,$t_out_pkts,$t_out_bytes,,,$t_in_pkts,$t_in_bytes,," >>"$csv"
printf '\n  TOTAL generated (OUTPUT): %s pkts, %s bytes over %ss = %s kbit/s of control overhead\n' \
    "$t_out_pkts" "$t_out_bytes" "$WINDOW" \
    "$(awk -v b="$t_out_bytes" -v w="$WINDOW" 'BEGIN{printf "%.1f", b*8/w/1000}')"
printf '  -> %s\n' "$csv"
